class Solution:
    def maximumXorProduct(self, a, b, n):
        MOD = 10 ** 9 + 7
        best = -1
        for x in range(1 << n):
            v = (a ^ x) * (b ^ x)
            if v > best:
                best = v
        return best % MOD

