class Solution:
    def maximumXorProduct(self, a, b, n):
        MOD = 10 ** 9 + 7
        for i in range(n - 1, -1, -1):
            abit = (a >> i) & 1
            bbit = (b >> i) & 1
            if abit == bbit:
                if abit == 0:
                    a |= (1 << i)
                    b |= (1 << i)
            else:
                if a < b:
                    a |= (1 << i)
                    b &= ~(1 << i)
                else:
                    b |= (1 << i)
                    a &= ~(1 << i)
        return (a % MOD) * (b % MOD) % MOD

