var maximumXorProduct = function(a, b, n) {
    const MOD = 1000000007n;
    let A = BigInt(a), B = BigInt(b);
    for (let i = n - 1; i >= 0; i--) {
        const bit = 1n << BigInt(i);
        const abit = (A >> BigInt(i)) & 1n;
        const bbit = (B >> BigInt(i)) & 1n;
        if (abit === bbit) {
            if (abit === 0n) {
                A |= bit;
                B |= bit;
            }
        } else {
            if (A < B) {
                A |= bit;
                B &= ~bit;
            } else {
                B |= bit;
                A &= ~bit;
            }
        }
    }
    return Number(((A % MOD) * (B % MOD)) % MOD);
};
